#include <mutex>

std::mutex m_usbMutex;

void CISPDockingDlg::SendFirmwareUpdate(const uint8_t* pBuffer, DWORD dwSize)
{
    m_usbMutex.lock();
    BOOL bResult = m_pDevice->Write(pBuffer, dwSize);
    if (!bResult) {
        // Early return — m_usbMutex.unlock() is never called!
        return;
    }
    m_usbMutex.unlock();
}
